(function(){var btns=document.querySelectorAll(".gallery-filter-btn");var items=document.querySelectorAll(".gallery-item");btns.forEach(function(btn){btn.addEventListener("click",function(){btns.forEach(function(b){b.classList.remove("active");});btn.classList.add("active");var f=btn.getAttribute("data-filter");items.forEach(function(item){if(f==="all"||item.getAttribute("data-category")===f){item.style.display="";}else{item.style.display="none";}});});});var lb=document.getElementById("galleryLightbox");var lbImg=document.getElementById("lbImage");var lbCounter=document.getElementById("lbCounter");var currentIdx=0;var visibleImgs=[];function getVisible(){visibleImgs=[];items.forEach(function(item){if(item.style.display!=="none"){visibleImgs.push(item.querySelector("img").src);}});}function showLb(idx){getVisible();if(idx<0)idx=visibleImgs.length-1;if(idx>=visibleImgs.length)idx=0;currentIdx=idx;lbImg.src=visibleImgs[idx];lbCounter.textContent=(idx+1)+" / "+visibleImgs.length;lb.classList.add("active");}items.forEach(function(item,i){item.addEventListener("click",function(){getVisible();var src=item.querySelector("img").src;var idx=visibleImgs.indexOf(src);showLb(idx>=0?idx:0);});});document.getElementById("lbClose").addEventListener("click",function(){lb.classList.remove("active");});document.getElementById("lbPrev").addEventListener("click",function(e){e.stopPropagation();showLb(currentIdx-1);});document.getElementById("lbNext").addEventListener("click",function(e){e.stopPropagation();showLb(currentIdx+1);});lb.addEventListener("click",function(e){if(e.target===lb)lb.classList.remove("active");});document.addEventListener("keydown",function(e){if(!lb.classList.contains("active"))return;if(e.key==="Escape")lb.classList.remove("active");if(e.key==="ArrowLeft")showLb(currentIdx-1);if(e.key==="ArrowRight")showLb(currentIdx+1);});})();